code: def edit_files(self, filenames: cabc.Iterable[str]) -> None:
    import subprocess

    editor = self.get_editor()
    environ: dict[str, str] | None = None

    if self.env:
        environ = os.environ.copy()
        environ.update(self.env)

    exc_filename = " ".join(f'"{filename}"' for filename in filenames)

    popen_kwargs: dict[str, t.Any] = {}

    if self.process_priority is not None:
        if WIN:
            priority_map = {
                "low": subprocess.IDLE_PRIORITY_CLASS,
                "below_normal": subprocess.BELOW_NORMAL_PRIORITY_CLASS,
                "normal": subprocess.NORMAL_PRIORITY_CLASS,
                "above_normal": subprocess.ABOVE_NORMAL_PRIORITY_CLASS,
                "high": subprocess.HIGH_PRIORITY_CLASS,
            }
            creationflags = priority_map.get(self.process_priority)
            if creationflags is not None:
                popen_kwargs["creationflags"] = creationflags
        else:
            nice_map = {
                "low": 10,
                "below_normal": 5,
                "normal": 0,
                "above_normal": -5,
                "high": -10,
            }
            nice_value = nice_map.get(self.process_priority)
            if nice_value is not None:

                def _set_priority(nice_value: int = nice_value) -> None:
                    try:
                        os.nice(nice_value)
                    except OSError:
                        pass

                popen_kwargs["preexec_fn"] = _set_priority

    try:
        c = subprocess.Popen(
            f"{editor} {exc_filename}", env=environ, shell=True, **popen_kwargs
        )
        exit_code = c.wait()
        if exit_code != 0:
            raise ClickException(
                _("{editor}: Editing failed").format(editor=editor)
            )
    except OSError as e:
        raise ClickException(
            _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
        ) from e
